import json,glob,os,re
terms=['周到','来福来财']
for p in glob.glob(os.path.expanduser('~/.openclaw/agents/*/sessions/sessions.json')):
    with open(p) as f: data=json.load(f)
    hits=[]
    for sid,obj in data.items():
        blob=json.dumps({'sid':sid, **obj}, ensure_ascii=False)
        if any(t in blob for t in terms):
            hits.append((sid,obj.get('origin'),obj.get('deliveryContext')))
    if hits:
        print('\nFILE',p)
        for sid,origin,delivery in hits:
            print('SID',sid)
            print(' origin',origin)
            print(' delivery',delivery)
